    fewShotCategory: 'auto',
  },
  verifierConfig: {
    autoCheck: true,
    semanticReview: true,
    autoFix: false,
  },
  fslockConfig: {
    enabled: true,
    timeoutMs: 30000,
  },
  budgetConfig: {
    enabled: false,
    totalTokens: 500000,
    autoRebalance: true,
    verifierReservePercent: 10,
    thresholds: { warning: 0.70, critical: 0.85, exhaust: 0.95 },
  },
};

class ConfigManager {
  private config: WorkflowConfig;

  constructor() {
    this.config = this.loadConfig();
  }

  private loadConfig(): WorkflowConfig {
    if (fs.existsSync(CONFIG_PATH)) {
      try {
        const data = fs.readFileSync(CONFIG_PATH, 'utf-8');
        return { ...defaultConfig, ...JSON.parse(data) };
      } catch (e) {
        return { ...defaultConfig };
      }
    }
    return { ...defaultConfig };

  }

  private saveConfig() {
    fs.writeFileSync(CONFIG_PATH, JSON.stringify(this.config, null, 2), 'utf-8');
  }

  get(): WorkflowConfig {
    // Reload dynamically to support multi-process changes
    this.config = this.loadConfig();
    return this.config;
  }

  update(newConfig: Partial<WorkflowConfig>) {
    this.config = { ...this.loadConfig(), ...newConfig };
    this.saveConfig();
  }
}

