import * as fs from 'fs';

// ============================================================================
// Types
// ============================================================================

export type LockMode = 'read' | 'write';

export interface FileLock {
  path: string;
  ownerAgentId: string;
  mode: LockMode;
  acquiredAt: number;
  reentryCount: number;
}

export interface WriteQueueItem {
  path: string;
  agentId: string;
  resolve: () => void;
  reject: (err: Error) => void;
}

export interface ConflictRecord {
  file: string;
  agents: string[];
  timestamp: number;
}

export interface FSLockConfig {
  enabled: boolean;
  timeoutMs: number; // 锁超时自动释放 (默认 30000)
}

// ============================================================================
// FileLockManager

// ============================================================================

export class FileLockManager {
  private static instance: FileLockManager;

  /** 当前持有的锁: filePath → FileLock */
  private locks: Map<string, FileLock> = new Map();

  /** 等待队列: filePath → 排队中的写请求列表 */
  private writeQueues: Map<string, WriteQueueItem[]> = new Map();

  /** 冲突日志: 被多个 Agent 写入的文件记录 */
  private conflictLog: ConflictRecord[] = [];

  /** 每个文件的写入历史: filePath → [agentId, ...] */
  private writeHistory: Map<string, string[]> = new Map();

  /** 活跃超时计时器: filePath → Timer */
  private timeoutTimers: Map<string, NodeJS.Timeout> = new Map();

  /** 全局开关 */
  private config: FSLockConfig = {
    enabled: true,
    timeoutMs: 30000,
  };

  private constructor() {}

  /** 获取单例 */
  static getInstance(): FileLockManager {
    if (!FileLockManager.instance) {
      FileLockManager.instance = new FileLockManager();
    }
    return FileLockManager.instance;
  }

  /** 更新配置 */
  configure(config: Partial<FSLockConfig>): void {
    this.config = { ...this.config, ...config };
  }

  /** 重置（测试用） */
  reset(): void {
    for (const timer of this.timeoutTimers.values()) {
      clearTimeout(timer);
    }
    this.locks.clear();
    this.writeQueues.clear();
    this.conflictLog = [];
    this.writeHistory.clear();

    this.timeoutTimers.clear();
  }

  // ==========================================================================
  // 公共 API
  // ==========================================================================

  /**
   * 获取写锁（互斥）
   *
   * - 如果文件未被锁定 → 立即获得锁
   * - 如果文件已被其他 Agent 持有锁 → 进入等待队列
   * - 同一 Agent 重复请求同一文件 → 直接返回（重入）
   */
  async acquireWrite(filePath: string, agentId: string): Promise<void> {
    if (!this.config.enabled) return;

    const normalizedPath = this.normalizePath(filePath);
    const existing = this.locks.get(normalizedPath);

    // 同一 Agent 已持有该文件的写锁 → 重入
    if (existing && existing.ownerAgentId === agentId && existing.mode === 'write') {
      existing.reentryCount++;
      return;
    }

    // 文件被其他 Agent 锁定 → 入队等待
    if (existing) {
      return new Promise<void>((resolve, reject) => {
        const queue = this.writeQueues.get(normalizedPath) || [];
        queue.push({ path: normalizedPath, agentId, resolve, reject });
        this.writeQueues.set(normalizedPath, queue);
      });
    }

    // 立即获取锁
    this.grantWriteLock(normalizedPath, agentId);
  }

  /**
   * 获取读锁（共享，不阻塞）
   *
   * 读锁不互斥，但记录访问者供冲突检测使用。
   */
  async acquireRead(filePath: string, agentId: string): Promise<void> {
    if (!this.config.enabled) return;

    const normalizedPath = this.normalizePath(filePath);
    const existing = this.locks.get(normalizedPath);

    // 有写锁 → 仍允许读（读取的是当前写入前的版本这取决于时序）
    // 这里只记录，不阻塞
    if (!existing) {
      this.locks.set(normalizedPath, {
        path: normalizedPath,
        ownerAgentId: agentId,
        mode: 'read',
        acquiredAt: Date.now(),
        reentryCount: 0,
      });
      // 读锁没有超时，因为不阻塞他人
    }
  }

  /**
   * 释放锁
   */
  release(filePath: string, agentId: string): void {
    if (!this.config.enabled) return;

    const normalizedPath = this.normalizePath(filePath);
    const existing = this.locks.get(normalizedPath);

    // 锁不属于此 Agent → 忽略
    if (!existing || existing.ownerAgentId !== agentId) {
      return;
    }

    // 处理重入释放
    if (existing.reentryCount > 0) {
      existing.reentryCount--;
      return;
    }

    // 清除超时计时器
    const timer = this.timeoutTimers.get(normalizedPath);
    if (timer) {
      clearTimeout(timer);
      this.timeoutTimers.delete(normalizedPath);
    }

    // 释放锁
    this.locks.delete(normalizedPath);

    // 记录写入历史
    if (existing.mode === 'write') {
      const history = this.writeHistory.get(normalizedPath) || [];
      if (!history.includes(agentId)) {
        history.push(agentId);
        this.writeHistory.set(normalizedPath, history);

      }

      // 如果多个 Agent 写过同一文件 → 记录冲突
      if (history.length > 1) {
        this.conflictLog.push({
          file: normalizedPath,
          agents: [...history],
          timestamp: Date.now(),
        });
      }
    }

    // 处理等待队列中的下一个请求
    this.processQueue(normalizedPath);
  }

  /**
   * 同步安全写入封装
   * 确保执行底层写入的那一刻，Agent 仍然实际持有锁（防止超时剥夺引发脏写）
   */
  writeFile(filePath: string, agentId: string, content: string): void {
    const normalizedPath = this.normalizePath(filePath);
    
    if (this.config.enabled) {
      const existing = this.locks.get(normalizedPath);
      if (!existing || existing.ownerAgentId !== agentId || existing.mode !== 'write') {
        throw new Error(`Write failed: Agent ${agentId} does not hold a write lock for ${filePath}. The lock may have timed out and been released.`);
      }
    }
    
    fs.writeFileSync(filePath, content, 'utf-8');
  }

  /**
   * Agent 任务结束时的批量释放
   */
  releaseAll(agentId: string): void {
    for (const [path, lock] of this.locks.entries()) {
      if (lock.ownerAgentId === agentId) {
        this.release(path, agentId);
      }
    }
  }

  /**
   * 返回冲突日志，供 Verifier 使用
   */
  getConflictLog(): ConflictRecord[] {
    return [...this.conflictLog];
  }

  /**
   * 检查文件当前是否被锁定
   */
  isLocked(filePath: string): boolean {
    return this.locks.has(this.normalizePath(filePath));
  }

  /**
   * 获取文件当前的锁信息
   */
  getLockInfo(filePath: string): FileLock | undefined {
    return this.locks.get(this.normalizePath(filePath));
  }

  /**
   * 获取写入历史（所有被写入过的文件及其 Agent 列表）
   */
  getWriteHistory(): Map<string, string[]> {
    return new Map(this.writeHistory);
  }

  // ==========================================================================
  // 私有方法
  // ==========================================================================

  private normalizePath(filePath: string): string {
    return filePath.replace(/\\/g, '/').replace(/\/+$/, '');
  }

  private grantWriteLock(normalizedPath: string, agentId: string): void {
    this.locks.set(normalizedPath, {
      path: normalizedPath,
      ownerAgentId: agentId,
      mode: 'write',
      acquiredAt: Date.now(),
      reentryCount: 0,
    });

    // 设置超时计时器
    const timer = setTimeout(() => {
      const lock = this.locks.get(normalizedPath);
      if (lock && lock.ownerAgentId === agentId) {
        console.warn(
          `[FSLock] Write lock timeout for "${normalizedPath}" (agent: ${agentId}). Auto-releasing.`
        );
        this.release(normalizedPath, agentId);
      }
    }, this.config.timeoutMs);

    this.timeoutTimers.set(normalizedPath, timer);
  }

  private processQueue(normalizedPath: string): void {
    const queue = this.writeQueues.get(normalizedPath);
    if (!queue || queue.length === 0) return;

    // 取出队列头部
    const next = queue.shift()!;

    if (queue.length === 0) {
      this.writeQueues.delete(normalizedPath);
    }

    // 授予写锁
    this.grantWriteLock(normalizedPath, next.agentId);
    next.resolve();
  }
}

// 导出单例获取函数（便捷用法）
export const fslock = (): FileLockManager => FileLockManager.getInstance();

import * as fs from 'fs';
import * as path from 'path';
import { workflowEvents } from './events';

export interface CodeChunk {
  file: string;
  content: string;
  startLine: number;
}

export class ProjectIndexer {
  private index: any = null;
  private extractFeatures: any = null;
  private chunksMap: Map<number, CodeChunk> = new Map();
  private numElements = 0;
  private indexPath: string;
  private metadataPath: string;
  private initialized = false;

  constructor(private cwd: string = process.cwd(), private dim: number = 384) {
    const workflowDir = path.join(cwd, '.workflow', 'index');
    if (!fs.existsSync(workflowDir)) {
      fs.mkdirSync(workflowDir, { recursive: true });
    }
    this.indexPath = path.join(workflowDir, 'hnsw.bin');
    this.metadataPath = path.join(workflowDir, 'metadata.json');
  }

  async init() {
    if (this.initialized) return;

    // 动态导入以避免原生模块急切加载导致的崩溃
    const { pipeline } = await import('@xenova/transformers');
    const hnswlib = (await import('hnswlib-node')).default;

    this.index = new hnswlib.HierarchicalNSW('cosine', this.dim);
    this.extractFeatures = await pipeline('feature-extraction', 'Xenova/all-MiniLM-L6-v2');

    if (fs.existsSync(this.indexPath) && fs.existsSync(this.metadataPath)) {
      try {
        const metadata = JSON.parse(fs.readFileSync(this.metadataPath, 'utf-8'));
        this.numElements = metadata.numElements;
        this.chunksMap = new Map(metadata.chunks.map((c: any) => [c.id, c.chunk]));
        this.index.readIndexSync(this.indexPath);
      } catch (e) {
        // 如果损坏，重新初始化
        this.index.initIndex(10000);
        this.numElements = 0;
      }
    } else {

    this.index.initIndex(10000);
  }

  this.initialized = true;
}

async getEmbedding(text: string): Promise<number[]> {
  const out = await this.extractFeatures(text, { pooling: 'mean', normalize: true });
  return Array.from(out.data);
}

async scanAndIndex() {
  await this.init();
  if (this.numElements > 0) return; // 已经建过索引

  workflowEvents.emit('log', { taskId: 'orchestrator', message: 'Building local code index for RAG (this may take a moment)...' });

  const exts = ['.ts', '.js', '.py', '.c', '.cpp', '.h', '.java', '.go', '.cs'];
  const files = this.walkDir(this.cwd, exts);

  for (const file of files) {
    try {
      const content = fs.readFileSync(file, 'utf-8');
      const lines = content.split('\n');

      // 简易按块分割 (每 50 行一块)
      for (let i = 0; i < lines.length; i += 50) {
        const chunkLines = lines.slice(i, i + 50);
        const chunkContent = chunkLines.join('\n');
        if (chunkContent.trim().length < 20) continue;

        const embedding = await this.getEmbedding(chunkContent);
        this.chunksMap.set(this.numElements, {
          file: path.relative(this.cwd, file).replace(/\\/g, '/'),
          content: chunkContent,
          startLine: i + 1
        });
        this.index.addPoint(embedding, this.numElements);
        this.numElements++;
      }
    } catch (e) {
      // ignore read errors
    }
  }

  // 保存
  if (this.numElements > 0) {
    this.index.writeIndexSync(this.indexPath);
    const chunksArray = Array.from(this.chunksMap.entries()).map(([id, chunk]) => ({ id, chunk }));
    fs.writeFileSync(this.metadataPath, JSON.stringify({ numElements: this.numElements, chunks: chunksArray }));

      workflowEvents.emit('log', { taskId: 'orchestrator', message: `Indexed ${this.numElements} code chunks successfully.` });
    }
  }

  async search(query: string, topK: number = 3): Promise<CodeChunk[]> {
    await this.init();
    if (this.numElements === 0) return [];

    const embedding = await this.getEmbedding(query);
    const result = this.index.searchKnn(embedding, Math.min(topK, this.numElements));

    return result.neighbors.map((idx: number) => this.chunksMap.get(idx)!);
  }

  private walkDir(dir: string, exts: string[]): string[] {
    let results: string[] = [];
    let list: string[] = [];
    try {
      list = fs.readdirSync(dir);
    } catch {
      return results;
    }

    for (const file of list) {
      if (['node_modules', '.git', 'dist', 'build', '.workflow'].includes(file)) continue;
      const fullPath = path.join(dir, file);
      try {
        const stat = fs.statSync(fullPath);
        if (stat && stat.isDirectory()) {
          results = results.concat(this.walkDir(fullPath, exts));
        } else {
          if (exts.includes(path.extname(fullPath))) {
            results.push(fullPath);
          }
        }
      } catch (e) {}
    }
    return results;
  }
}

import * as fs from 'fs';
import * as path from 'path';

const MEMORY_FILE = '.autocoderc';

/**
 * 获取项目维度的长期记忆（规范、偏好、踩过的坑）
 */
export function getProjectMemory(cwd: string = process.cwd()): string {
  const memoryPath = path.join(cwd, MEMORY_FILE);
  if (fs.existsSync(memoryPath)) {
    return fs.readFileSync(memoryPath, 'utf-8').trim();
  }
  return '';
}

/**
 * 向长期记忆中追加新的规范或经验教训
 */
export function appendProjectMemory(newRule: string, cwd: string = process.cwd()): void {
  const memoryPath = path.join(cwd, MEMORY_FILE);
  let content = '';
  if (fs.existsSync(memoryPath)) {
    content = fs.readFileSync(memoryPath, 'utf-8').trim();
  }
  content += (content.length > 0 ? '\n' : '') + newRule;
  fs.writeFileSync(memoryPath, content, 'utf-8');
}

/**
 * Decomposer — 智能任务拆解引擎
 *
 * 核心流程：
 * 1. 分类用户输入 → 匹配 few-shot 模板
 * 2. LLM 拆解（结构化 JSON 输出）
 * 3. 自检（可选）→ 修复隐式依赖和文件冲突
 * 4. 拓扑排序 → 输出并行批次
 */

import type { Subtask, DecompositionResult, DecomposerConfig } from './types';
import { DEFAULT_DECOMPOSER_CONFIG } from './types';
import {
  detectCategory,
  buildDecompositionPrompt,
  buildSelfCheckPrompt,
} from './templates';

// ============================================================================
// Types
// ============================================================================

export interface LLMCallOptions {
  /** 模型名 */
  model?: string;
  /** Temperature */
  temperature?: number;
  /** 最大输出 token */
  maxTokens?: number;
}

export interface DecomposerDependencies {
  /** LLM 调用函数（由上层注入） */
  callLLM: (prompt: string, options?: LLMCallOptions) => Promise<string>;
}

// ============================================================================
// SelfCheckResult
// ============================================================================

interface SelfCheckResult {
  missingDependencies: { from: string; to: string; reason: string }[];
  fileConflicts: { file: string; taskA: string; taskB: string }[];
  overlyCoarse: string[];
  overlyFine: string[];
  warnings: string[];
}

// ============================================================================
// Decomposer

// ============================================================================

export class Decomposer {
  private config: DecomposerConfig;
  private llm: DecomposerDependencies;

  constructor(llm: DecomposerDependencies, config?: Partial<DecomposerConfig>) {
    this.llm = llm;
    this.config = { ...DEFAULT_DECOMPOSER_CONFIG, ...config };
  }

  updateConfig(config: Partial<DecomposerConfig>): void {
    this.config = { ...this.config, ...config };
  }

  // ==========================================================================
  // 公共 API
  // ==========================================================================

  /**
   * 将用户任务分解为子任务
   *
   * @param userInput 用户的自然语言任务描述
   * @param projectMemory 项目的长期记忆上下文
   * @returns 拆解结果（含并行批次）
   */
  async decompose(userInput: string, projectMemory: string = ''): Promise<DecompositionResult> {
    const warnings: string[] = [];

    // Step 1: 分类
    const category = this.config.fewShotCategory === 'auto'
      ? detectCategory(userInput)
      : this.config.fewShotCategory;

    // Step 2: LLM 拆解
    const prompt = buildDecompositionPrompt(userInput, category, this.config, projectMemory);
    const rawResponse = await this.llm.callLLM(prompt, {
      temperature: 0.3,
      maxTokens: 4000,
    });

    let subtasks = this.parseSubtasks(rawResponse);
    if (subtasks.length === 0) {
      // 解析失败 → 创建单个回退任务
      warnings.push('LLM 拆解返回空结果，使用单任务回退');
      subtasks = [this.createFallbackTask(userInput)];
    }

    // 限制数量
    if (subtasks.length > this.config.maxSubtasks) {

      warnings.push(
        `子任务数量 ${subtasks.length} 超过上限 ${this.config.maxSubtasks}，已截断`
      );
      subtasks = subtasks.slice(0, this.config.maxSubtasks);
    }

    // Step 3: 自检（可选）
    if (this.config.enableSelfCheck) {
      const selfCheckResult = await this.selfCheck(subtasks);
      subtasks = this.applySelfCheck(subtasks, selfCheckResult);
      warnings.push(...selfCheckResult.warnings);
    }

    // Step 4: 构建 DAG + 拓扑排序
    const dependencyGraph = this.buildDependencyGraph(subtasks);
    const parallelBatches = this.topoSortBatches(subtasks, dependencyGraph);

    // 验证 DAG 无环
    if (!this.isAcyclic(subtasks, dependencyGraph)) {
      warnings.push('检测到循环依赖！已退化为顺序执行');
      return {
        subtasks,
        dependencyGraph,
        parallelBatches: subtasks.map((t) => [t]), // 逐个执行
        warnings,
      };
    }

    return {
      subtasks,
      dependencyGraph,
      parallelBatches,
      warnings,
    };
  }

  // ==========================================================================
  // 私有方法
  // ==========================================================================

  /**
   * 从 LLM 返回文本中解析 JSON
   */
  private parseSubtasks(raw: string): Subtask[] {
    // 尝试直接解析
    let json: unknown;

    // 先尝试从 ```json 代码块提取
    const jsonBlockMatch = raw.match(/```(?:json)?\s*\n?([\s\S]*?)```/);
    const jsonStr = (jsonBlockMatch?.[1] ?? raw).trim();

    try {
      json = JSON.parse(jsonStr);
    } catch {
      // 尝试修复常见问题：单引号 → 双引号
      try {
        json = JSON.parse(jsonStr.replace(/'/g, '"'));
      } catch {
        return [];
      }
    }

    if (!Array.isArray(json)) return [];

    return json
      .filter((item): item is Record<string, unknown> => typeof item === 'object' && item !== null)
      .map((item) => this.normalizeSubtask(item))
      .filter((t): t is Subtask => t !== null);
  }

  private normalizeSubtask(item: Record<string, unknown>): Subtask | null {
    if (!item.id || !item.description) return null;

    return {
      id: String(item.id),
      description: String(item.description),
      estimatedComplexity: this.clamp(
        Number(item.estimatedComplexity) || 5,
        1,
        10
      ),
      dependencies: Array.isArray(item.dependencies)
        ? item.dependencies.map(String)
        : [],
      isolatedFiles: Array.isArray(item.isolatedFiles)
        ? item.isolatedFiles.map(String)
        : [],
      sharedFiles: Array.isArray(item.sharedFiles)
        ? item.sharedFiles.map(String)
        : [],
      expectedOutput: String(item.expectedOutput || ''),
    };
  }

  /**
   * LLM 自检
   */
  private async selfCheck(subtasks: Subtask[]): Promise<SelfCheckResult> {
    const prompt = buildSelfCheckPrompt(subtasks);
    const response = await this.llm.callLLM(prompt, {

      temperature: 0.1,
      maxTokens: 2000,
    });

    const jsonMatch = response.match(/```(?:json)?\s*\n?([\s\S]*?)```/);
    const jsonStr = (jsonMatch?.[1] ?? response).trim();

    try {
      return JSON.parse(jsonStr);
    } catch {
      return {
        missingDependencies: [],
        fileConflicts: [],
        overlyCoarse: [],
        overlyFine: [],
        warnings: [],
      };
    }
  }

  /**
   * 应用自检结果，修复 Subtask 列表
   */
  private applySelfCheck(subtasks: Subtask[], result: SelfCheckResult): Subtask[] {
    const taskMap = new Map(subtasks.map((t) => [t.id, { ...t }]));

    // 添加缺失依赖
    for (const { from, to } of result.missingDependencies) {
      const task = taskMap.get(from);
      if (task && !task.dependencies.includes(to)) {
        task.dependencies = [...task.dependencies, to];
      }
    }

    // 修复文件冲突：将 conflict 文件分配给 complexity 更高的 Agent
    for (const { file, taskA, taskB } of result.fileConflicts) {
      const a = taskMap.get(taskA);
      const b = taskMap.get(taskB);
      if (a && b) {
        const winner = (a.estimatedComplexity >= b.estimatedComplexity) ? a : b;
        const loser = (a.estimatedComplexity >= b.estimatedComplexity) ? b : a;
        // 失败者从 isolatedFiles 中移除该文件
        loser.isolatedFiles = loser.isolatedFiles.filter((f) => f !== file);
        // 添加到 sharedFiles（只读）
        if (!loser.sharedFiles.includes(file)) {
          loser.sharedFiles = [...loser.sharedFiles, file];
        }
      }
    }

    return Array.from(taskMap.values());
  }

  /**
   * 构建依赖图邻接表
   */
  private buildDependencyGraph(subtasks: Subtask[]): Map<string, string[]> {
    const graph = new Map<string, string[]>();
    for (const t of subtasks) {
      graph.set(t.id, t.dependencies);
    }
    return graph;
  }

  /**
   * 拓扑排序，按层级分组
   * 第 0 层 = 无依赖，第 1 层 = 只依赖第 0 层，以此类推
   */
  private topoSortBatches(
    subtasks: Subtask[],
    graph: Map<string, string[]>
  ): Subtask[][] {
    const taskMap = new Map(subtasks.map((t) => [t.id, t]));
    const inDegree = new Map<string, number>();
    const dependents = new Map<string, string[]>(); // taskId → 依赖它的 taskIds

    for (const t of subtasks) {
      inDegree.set(t.id, t.dependencies.length);
      for (const dep of t.dependencies) {
        const list = dependents.get(dep) || [];
        list.push(t.id);
        dependents.set(dep, list);
      }
    }

    const batches: Subtask[][] = [];
    let queue = Array.from(inDegree.entries())
      .filter(([, deg]) => deg === 0)
      .map(([id]) => id);

    while (queue.length > 0) {
      const batch = queue
        .map((id) => taskMap.get(id)!)
        .filter(Boolean);
      batches.push(batch);

      const nextQueue: string[] = [];
      for (const taskId of queue) {
        const deps = dependents.get(taskId) || [];
        for (const depId of deps) {

          const newDeg = (inDegree.get(depId) || 0) - 1;
          inDegree.set(depId, newDeg);
          if (newDeg === 0) {
            nextQueue.push(depId);
          }
        }
      }
      queue = nextQueue;
    }

    return batches;
  }

  /**
   * 检测 DAG 是否有环（基于 DFS 的三色标记法）
   */
  private isAcyclic(
    subtasks: Subtask[],
    graph: Map<string, string[]>
  ): boolean {
    const WHITE = 0, GRAY = 1, BLACK = 2;
    const color = new Map<string, number>();
    for (const t of subtasks) color.set(t.id, WHITE);

    const dfs = (node: string): boolean => {
      color.set(node, GRAY);
      for (const dep of graph.get(node) || []) {
        if (color.get(dep) === GRAY) return false; // 环检测
        if (color.get(dep) === WHITE && !dfs(dep)) return false;
      }
      color.set(node, BLACK);
      return true;
    };

    for (const t of subtasks) {
      if (color.get(t.id) === WHITE && !dfs(t.id)) {
        return false;
      }
    }
    return true;
  }

  private createFallbackTask(userInput: string): Subtask {
    return {
      id: 'fallback-1',
      description: userInput,
      estimatedComplexity: 8,
      dependencies: [],
      isolatedFiles: [],
      sharedFiles: [],

      expectedOutput: '完成用户任务',
    };
  }

  private clamp(value: number, min: number, max: number): number {
    return Math.max(min, Math.min(max, value));
  }
}

