  constructor() {
    const config = this.loadOrchestratorConfig();
    this.decomposer = new Decomposer(
      {
        callLLM: async (prompt, opts) => {
          const response = await askLLM(
            prompt,
            [{ role: 'user', content: prompt }],
            undefined,
            undefined,
            opts?.temperature ?? 0.3,
            'orchestrator'
