  private loadOrchestratorConfig(): DecomposerConfig {
    try {
      const config = GlobalConfig.get() as any;
      if (config.orchestratorConfig) {
        return { ...DEFAULT_DECOMPOSER_CONFIG, ...config.orchestratorConfig };
      }
