        description: t.description,
        expectedOutput: t.expectedOutput,
        estimatedComplexity: t.estimatedComplexity,
        dependencies: t.dependencies,
        isolatedFiles: t.isolatedFiles,
        sharedFiles: t.sharedFiles,
