    const textToEmbed = `${tool.name}: ${tool.description}`;
    const embedding = await this.getEmbedding(textToEmbed);
    
    this.toolsMap.set(this.numElements, tool);
    this.index.addPoint(embedding, this.numElements);
    this.numElements++;
  }

