                    self._buffer.popleft()
                    chunks.append(chunk)
                    remaining -= len(chunk)
                else:
                    chunks.append(chunk[:remaining])
                    self._buffer[0] = chunk[remaining:]
                    remaining = 0
                    break
            if remaining == 0:
                break
            if self.timeout == 0:
                break
            if self.timeout is not None:
                now = time.monotonic()
                if now >= deadline:
                    break
                wait = deadline - now
            else:
                wait = None
            if not self._cond.wait(timeout=wait):
                break

    data = b''.join(chunks)
    self.bytes_read += len(data)
    return data

def readline(self) -> bytes:
    """读取一行（直到换行符或超时）."""
    self._check_open()
    buffer = bytearray()
    deadline = None if self.timeout is None else (time.monotonic() + self.timeout)
    with self._cond:
        while True:
            while self._buffer:
                chunk = self._buffer[0]
                idx = chunk.find(b'\n')
                if idx >= 0:
                    # 找到换行符
                    take = chunk[:idx + 1]
                    rest = chunk[idx + 1:]
                    if rest:
                        self._buffer[0] = rest
                    else:
                        self._buffer.popleft()
                    buffer.extend(take)
                    result = bytes(buffer)
                    self.bytes_read += len(result)
